class Solution {
    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int n = buses.length, m = passengers.length;
        int low = 0, high = (int) 1e9;
        while (low < high) {
            int mid = low + (high - low) / 2;
            if (canCatchBus(mid, buses, passengers, capacity)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private boolean canCatchBus(int time, int[] buses, int[] passengers, int capacity) {
        int j = 0;
        for (int i = 0; i < buses.length; i++) {
            while (j < passengers.length && passengers[j] <= buses[i]) {
                j++;
            }
            int count = Math.min(j, capacity);
            if (i + 1 == buses.length || time <= buses[i + 1]) {
                return count <= capacity;
            }
            j -= count;
        }
        return false;
    }
}
